#!/usr/bin/bash
# 1. Create the credentials file 
#(The following line is generated by claude--opus-4.6, which cannot be executed because of the ! in the password)
# echo -e "admin:password123\njohndoe:securePass!\nalice:myP@ssw0rd" > credentials.txt 
# The following is the correct line to create the credentials file without issues. It uses '' to avoid the problem with the ! character in the password.
echo -e 'admin:password123\njohndoe:securePass!\nalice:myP@ssw0rd' > credentials.txt 

# 2. Create the build directory (added for gitignore)
mkdir -p build

# 3. Compile
gcc -Wall -Wextra -o build/auth claude-opus-4.6.c 

# 4. Run
./build/auth